# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import boto3
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from PIL import Image
import io

def take_screenshot(url):
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--window-size=1280x720")

    driver = webdriver.Chrome(options=chrome_options)
    driver.get(url)

    screenshot = driver.get_screenshot_as_png()
    driver.quit()

    image = Image.open(io.BytesIO(screenshot))
    image.thumbnail((300, 300))  # Resize to thumbnail size

    return image

def upload_to_s3(image, bucket_name, object_name):
    s3_client = boto3.client('s3')
    img_byte_arr = io.BytesIO()
    image.save(img_byte_arr, format='PNG')
    img_byte_arr.seek(0)

    s3_client.upload_fileobj(img_byte_arr, bucket_name, object_name)
    return f"https://{bucket_name}.s3.amazonaws.com/{object_name}"

def generate_thumbnail(url, bucket_name):
    image = take_screenshot(url)
    object_name = url.split('/')[-1] + '.png'
    thumbnail_url = upload_to_s3(image, bucket_name, object_name)
    return thumbnail_url

# Example usage
if __name__ == "__main__":
    url = "https://www.example.com"
    bucket_name = "your-s3-bucket-name"
    thumbnail_url = generate_thumbnail(url, bucket_name)
    print(f"Thumbnail URL: {thumbnail_url}")